pub fn iced_length_from_points(points: f32) -> iced::Length {
    iced::Length::Fixed(points.max(0.0))
}

pub fn iced_point(point: Point) -> iced::Point {
    iced::Point::new(point.x, point.y)
}

fn point_add(lhs: Point, rhs: Point) -> Point {
    Point {
        x: lhs.x + rhs.x,
        y: lhs.y + rhs.y,
    }
}

fn rect_translate(rect: Rect, offset: Point) -> Rect {
    Rect {
        origin: point_add(rect.origin, offset),
        size: rect.size,
    }
}

