impl<W, Theme, Renderer> iced::advanced::Widget<SlipwayIcedRuntimeMessage, Theme, Renderer>
    for SlipwayIcedRuntimeWidget<'_, W>
where
    W: SlipwayIcedBackendChildWidget,
    W::AppMessage: Clone,
    Theme: SlipwayIcedThemeContract,
    Renderer: iced::advanced::text::Renderer<Font = iced::Font>
        + iced::advanced::graphics::geometry::Renderer
        + 'static,
{
    fn tag(&self) -> iced::advanced::widget::tree::Tag {
        iced::advanced::widget::tree::Tag::of::<IcedRuntimeTreeState>()
    }

    fn state(&self) -> iced::advanced::widget::tree::State {
        iced::advanced::widget::tree::State::new(IcedRuntimeTreeState {
            id: self.widget.id(),
            slot: self.runtime_slot.clone(),
            presentation: None,
            text_edit_trees: Vec::new(),
            text_editor_trees: Vec::new(),
            scroll_region_trees: Vec::new(),
            hovered_region: None,
            pressed_region: None,
            indicator_drag: None,
            focused_region: None,
            published_preedit_style: None,
            layout_pass: 0,
        })
    }

    fn children(&self) -> Vec<iced::advanced::widget::Tree> {
        iced_runtime_child_trees::<W, Theme, Renderer>(
            self.widget,
            self.external,
            self.local,
            self.frame_seed.as_ref(),
            self.dirty_scopes.as_deref(),
            None,
        )
    }

    fn diff(&self, tree: &mut iced::advanced::widget::Tree) {
        let topology = self.widget.topology(self.external);
        let id = topology.id.clone();
        let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
        if state.id != id || state.slot != self.runtime_slot {
            state.id = id;
            state.slot = self.runtime_slot.clone();
            state.presentation = None;
            state.text_edit_trees.clear();
            state.text_editor_trees.clear();
            state.scroll_region_trees.clear();
            state.hovered_region = None;
            state.pressed_region = None;
            state.focused_region = None;
            state.layout_pass = 0;
        }
        let previous_child_context = state.presentation.as_ref().map(|presentation| {
            (
                presentation.frame.clone(),
                root_child_placements_excluding_native_scroll(presentation),
            )
        });
        reconcile_iced_runtime_child_trees::<W, Theme, Renderer>(
            self.widget,
            self.external,
            self.local,
            &mut tree.children,
            self.frame_seed.as_ref(),
            self.dirty_scopes.as_deref(),
            previous_child_context
                .as_ref()
                .map(|(frame, placements)| (frame, placements.as_ref())),
        );
    }

    fn size(&self) -> iced::Size<iced::Length> {
        iced::Size {
            width: self.width,
            height: self.height,
        }
    }

    fn layout(
        &mut self,
        tree: &mut iced::advanced::widget::Tree,
        renderer: &Renderer,
        limits: &iced::advanced::layout::Limits,
    ) -> iced::advanced::layout::Node {
        let input = iced_layout_input_from_limits(limits);
        self.record_presented_viewport(input.viewport.into_rect());
        let root_placements = {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            state.id = self.widget.id();
            if state.presentation.as_ref().is_some_and(|presentation| {
                iced_presentation_cache_matches(
                    presentation,
                    &input,
                    self.frame_seed.as_ref(),
                    self.dirty_scopes.as_deref(),
                    &state.id,
                    self.runtime_slot.as_ref(),
                    self.root_origin,
                )
            }) {
                if let Some(presentation) = state.presentation.as_mut() {
                    refresh_iced_presentation_frame(
                        presentation,
                        &input,
                        self.frame_seed.as_ref(),
                        &state.id,
                        state.layout_pass,
                    );
                }
            } else {
                state.layout_pass = state.layout_pass.saturating_add(1);
                state.presentation = Some(iced_presentation_for_widget_with_root_origin(
                    self.widget,
                    self.external,
                    self.local,
                    input,
                    self.frame_seed.as_ref(),
                    state.layout_pass,
                    self.runtime_slot.as_ref(),
                    self.root_origin,
                ));
            }
            if let Some(presentation) = state.presentation.as_mut() {
                presentation.apply_dispatch_context_override(self.dispatch_context.as_deref());
            }
            state
                .presentation
                .as_ref()
                .map(root_child_placements_excluding_native_scroll)
                .unwrap_or_default()
        };
        let (child_frame, root_origin, dispatch_context) = {
            let presentation = tree
                .state
                .downcast_ref::<IcedRuntimeTreeState>()
                .presentation
                .as_ref()
                .expect("runtime layout must create presentation before child layout");
            (
                presentation.frame.clone(),
                presentation.root_origin,
                presentation.dispatch_context.clone(),
            )
        };
        let mut child_nodes = layout_iced_runtime_children::<W, Theme, Renderer>(
            self.widget,
            self.external,
            self.local,
            &mut tree.children,
            renderer,
            root_placements.as_ref(),
            &child_frame,
            self.frame_seed.as_ref(),
            self.dirty_scopes.as_deref(),
            root_origin,
            Some(&dispatch_context),
        );
        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_mut()
                .expect("runtime layout must create presentation before child occlusion merge");
            merge_child_explicit_layer_occlusions_into_presentation(
                self.widget,
                self.external,
                self.local,
                presentation,
                root_placements.as_ref(),
                &tree.children,
            );
        }
        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime layout must create presentation before scroll layout");
            child_nodes.extend(layout_iced_scroll_regions::<W, Theme, Renderer>(
                &mut state.scroll_region_trees,
                self.widget,
                self.external,
                self.local,
                presentation,
                renderer,
                self.frame_seed.as_ref(),
                self.dirty_scopes.as_deref(),
            ));
        }
        let (text_input_regions, text_editor_regions) = {
            let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
            let presentation = state.presentation.as_ref();
            (
                presentation
                    .map(text_input_focus_regions)
                    .unwrap_or_default(),
                presentation
                    .map(text_editor_focus_regions)
                    .unwrap_or_default(),
            )
        };
        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            if let Some(presentation) = state.presentation.as_ref() {
                child_nodes.extend(layout_iced_text_editor_regions::<
                    W::AppMessage,
                    Theme,
                    Renderer,
                >(
                    &mut state.text_editor_trees,
                    renderer,
                    presentation,
                    text_editor_regions.as_ref(),
                ));
                child_nodes.extend(layout_iced_text_input_regions::<
                    W::AppMessage,
                    Theme,
                    Renderer,
                >(
                    &mut state.text_edit_trees,
                    renderer,
                    presentation,
                    text_input_regions.as_ref(),
                ));
            }
        }
        {
            // Refresh this presentation's flattened descendant hit regions from
            // the current mounted child presentations (already laid out above,
            // including native-scroll subtrees). This keeps a reused composite
            // presentation's `ViewRootLocal` dispatch geometry current after an
            // intra-child drag without a full composite rebuild.
            let mut child_hit_regions = std::collections::HashMap::new();
            {
                let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
                for scroll_tree in &state.scroll_region_trees {
                    collect_descendant_runtime_hit_regions(scroll_tree, &mut child_hit_regions);
                }
            }
            for child in &tree.children {
                collect_descendant_runtime_hit_regions(child, &mut child_hit_regions);
            }
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            if let Some(presentation) = state.presentation.as_mut() {
                refresh_composite_child_hit_regions(presentation, &child_hit_regions);
            }
        }
        let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
        let presentation = state
            .presentation
            .as_ref()
            .expect("runtime layout must create a presentation before building a node");
        let node = iced_node_for_presentation_with_children(
            self.width,
            self.height,
            limits,
            presentation,
            child_nodes,
        );
        node
    }

    fn operate(
        &mut self,
        tree: &mut iced::advanced::widget::Tree,
        layout: iced::advanced::Layout<'_>,
        renderer: &Renderer,
        operation: &mut dyn iced::advanced::widget::Operation,
    ) {
        let (
            root_placements,
            text_input_regions,
            text_editor_regions,
            frame,
            root_origin,
            dispatch_context,
        ) = {
            let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime operate must have presentation before child operation");
            (
                root_child_placements_excluding_native_scroll(presentation),
                text_input_focus_regions(presentation),
                text_editor_focus_regions(presentation),
                presentation.frame.clone(),
                presentation.root_origin,
                presentation.dispatch_context.clone(),
            )
        };
        let text_region_count = text_input_regions.len() + text_editor_regions.len();
        operate_iced_root_container(&self.widget.id(), layout, operation);
        operation.traverse(&mut |operation| {
            operate_iced_runtime_children::<W, Theme, Renderer>(
                self.widget,
                self.external,
                self.local,
                &mut tree.children,
                layout,
                renderer,
                operation,
                root_placements.as_ref(),
                &frame,
                self.frame_seed.as_ref(),
                self.dirty_scopes.as_deref(),
                root_origin,
                Some(&dispatch_context),
            );
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            if let Some(presentation) = state.presentation.as_ref() {
                operate_iced_scroll_regions::<W, Theme, Renderer>(
                    &mut state.scroll_region_trees,
                    self.widget,
                    self.external,
                    self.local,
                    presentation,
                    layout,
                    renderer,
                    operation,
                    text_region_count,
                    self.frame_seed.as_ref(),
                    self.dirty_scopes.as_deref(),
                );
            }
            if let Some(presentation) = state.presentation.as_ref() {
                operate_iced_text_editor_regions::<W::AppMessage, Theme, Renderer>(
                    &mut state.text_editor_trees,
                    presentation,
                    text_editor_regions.as_ref(),
                    text_input_regions.len(),
                    layout,
                    renderer,
                    operation,
                );
            }
            if let Some(presentation) = state.presentation.as_ref() {
                operate_iced_text_input_regions::<W::AppMessage, Theme, Renderer>(
                    &mut state.text_edit_trees,
                    presentation,
                    text_input_regions.as_ref(),
                    layout,
                    renderer,
                    operation,
                );
            }
        });
    }

    fn update(
        &mut self,
        tree: &mut iced::advanced::widget::Tree,
        event: &iced::Event,
        layout: iced::advanced::Layout<'_>,
        cursor: iced::advanced::mouse::Cursor,
        renderer: &Renderer,
        clipboard: &mut dyn iced::advanced::Clipboard,
        shell: &mut iced::advanced::Shell<'_, SlipwayIcedRuntimeMessage>,
        viewport: &iced::Rectangle,
    ) {
        if shell.is_event_captured() {
            return;
        }

        let (
            root_placements,
            text_input_regions,
            text_editor_regions,
            frame,
            root_origin,
            dispatch_context,
        ) = {
            let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime update must have presentation before child update");
            (
                root_child_placements_excluding_native_scroll(presentation),
                text_input_focus_regions(presentation),
                text_editor_focus_regions(presentation),
                presentation.frame.clone(),
                presentation.root_origin,
                presentation.dispatch_context.clone(),
            )
        };
        let text_region_count = text_input_regions.len() + text_editor_regions.len();

        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime update must have presentation before text editor update");
            update_iced_text_editor_regions::<W::AppMessage, Theme, Renderer>(
                &mut state.text_editor_trees,
                presentation,
                text_editor_regions.as_ref(),
                text_input_regions.len(),
                event,
                layout,
                cursor,
                renderer,
                clipboard,
                shell,
                viewport,
                &mut state.published_preedit_style,
            );
        }

        if shell.is_event_captured() {
            return;
        }

        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime update must have presentation before text input update");
            update_iced_text_input_regions::<W::AppMessage, Theme, Renderer>(
                &mut state.text_edit_trees,
                presentation,
                text_input_regions.as_ref(),
                event,
                layout,
                cursor,
                renderer,
                clipboard,
                shell,
                viewport,
                &mut state.published_preedit_style,
            );
        }

        if shell.is_event_captured() {
            return;
        }

        update_iced_runtime_children::<W, Theme, Renderer>(
            self.widget,
            self.external,
            self.local,
            &mut tree.children,
            event,
            layout,
            cursor,
            renderer,
            clipboard,
            shell,
            viewport,
            root_placements.as_ref(),
            &frame,
            self.frame_seed.as_ref(),
            self.dirty_scopes.as_deref(),
            root_origin,
            Some(&dispatch_context),
        );

        if shell.is_event_captured() {
            return;
        }

        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime update must have presentation before scroll update");
            update_iced_scroll_regions::<W, Theme, Renderer>(
                &mut state.scroll_region_trees,
                self.widget,
                self.external,
                self.local,
                presentation,
                event,
                layout,
                cursor,
                renderer,
                clipboard,
                shell,
                viewport,
                text_region_count,
                self.frame_seed.as_ref(),
                self.dirty_scopes.as_deref(),
            );
        }

        if shell.is_event_captured() {
            return;
        }

        let routed = {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            route_iced_event_for_tree_state(event, layout.bounds(), cursor, state)
        };
        let Some(routed) = routed else {
            return;
        };

        publish_iced_routed_input(shell, routed);
    }

    fn draw(
        &self,
        tree: &iced::advanced::widget::Tree,
        renderer: &mut Renderer,
        _theme: &Theme,
        style: &iced::advanced::renderer::Style,
        layout: iced::advanced::Layout<'_>,
        cursor: iced::advanced::mouse::Cursor,
        viewport: &iced::Rectangle,
    ) {
        with_iced_surface_global_paint_queue(renderer, |renderer| {
            draw_iced_runtime_widget_local::<W, Theme, Renderer>(
                self, tree, renderer, _theme, style, layout, cursor, viewport,
            );
        });
    }

    fn mouse_interaction(
        &self,
        tree: &iced::advanced::widget::Tree,
        layout: iced::advanced::Layout<'_>,
        cursor: iced::advanced::mouse::Cursor,
        viewport: &iced::Rectangle,
        renderer: &Renderer,
    ) -> iced::advanced::mouse::Interaction {
        let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
        let root_placements = state
            .presentation
            .as_ref()
            .map(root_child_placements_excluding_native_scroll)
            .unwrap_or_default();
        if let Some(presentation) = state.presentation.as_ref() {
            let child_interaction = iced_runtime_children_mouse_interaction::<W, Theme, Renderer>(
                self.widget,
                self.external,
                self.local,
                &tree.children,
                layout,
                cursor,
                viewport,
                renderer,
                root_placements.as_ref(),
                &presentation.frame,
                self.frame_seed.as_ref(),
                self.dirty_scopes.as_deref(),
                presentation.root_origin,
                Some(&presentation.dispatch_context),
            );
            if child_interaction != iced::advanced::mouse::Interaction::None {
                return child_interaction;
            }
        }
        let text_input_regions = state
            .presentation
            .as_ref()
            .map(text_input_focus_regions)
            .unwrap_or_default();
        let text_editor_regions = state
            .presentation
            .as_ref()
            .map(text_editor_focus_regions)
            .unwrap_or_default();
        let text_region_count = text_input_regions.len() + text_editor_regions.len();
        if let Some(presentation) = state.presentation.as_ref() {
            let scroll_interaction = iced_scroll_regions_mouse_interaction::<W, Theme, Renderer>(
                &state.scroll_region_trees,
                self.widget,
                self.external,
                self.local,
                presentation,
                layout,
                cursor,
                viewport,
                renderer,
                text_region_count,
                self.frame_seed.as_ref(),
                self.dirty_scopes.as_deref(),
            );
            if scroll_interaction != iced::advanced::mouse::Interaction::None {
                return scroll_interaction;
            }
        }
        let text_editor_interaction = state.presentation.as_ref().map_or(
            iced::advanced::mouse::Interaction::None,
            |presentation| {
                iced_text_editor_regions_mouse_interaction::<W::AppMessage, Theme, Renderer>(
                    &state.text_editor_trees,
                    presentation,
                    text_editor_regions.as_ref(),
                    text_input_regions.len(),
                    layout,
                    cursor,
                    viewport,
                    renderer,
                )
            },
        );
        if text_editor_interaction != iced::advanced::mouse::Interaction::None {
            return text_editor_interaction;
        }
        let text_interaction = state.presentation.as_ref().map_or(
            iced::advanced::mouse::Interaction::None,
            |presentation| {
                iced_text_input_regions_mouse_interaction::<W::AppMessage, Theme, Renderer>(
                    &state.text_edit_trees,
                    presentation,
                    text_input_regions.as_ref(),
                    layout,
                    cursor,
                    viewport,
                    renderer,
                )
            },
        );
        if text_interaction != iced::advanced::mouse::Interaction::None {
            return text_interaction;
        }
        mouse_interaction_for_presentation(layout.bounds(), cursor, state.presentation.as_ref())
    }

    fn overlay<'b>(
        &'b mut self,
        _tree: &'b mut iced::advanced::widget::Tree,
        _layout: iced::advanced::Layout<'b>,
        _renderer: &Renderer,
        _viewport: &iced::Rectangle,
        _translation: iced::Vector,
    ) -> Option<iced::advanced::overlay::Element<'b, SlipwayIcedRuntimeMessage, Theme, Renderer>>
    {
        // Current core overlay declarations are metadata-only: they do not expose stable authored
        // overlay child/surface content, tree identity, layout, event routing, or an iced-safe
        // lifetime path. Returning an overlay here would fake official iced overlay forwarding.
        None
    }
}

impl<W, Theme, Renderer> iced::advanced::Widget<SlipwayIcedRuntimeMessage, Theme, Renderer>
    for SlipwayIcedRuntimeLayoutIntentWidget<'_, W>
where
    W: SlipwayIcedLayoutIntentBackendChildWidget,
    W::AppMessage: Clone,
    Theme: SlipwayIcedThemeContract,
    Renderer: iced::advanced::text::Renderer<Font = iced::Font>
        + iced::advanced::graphics::geometry::Renderer
        + 'static,
{
    fn tag(&self) -> iced::advanced::widget::tree::Tag {
        iced::advanced::widget::tree::Tag::of::<IcedRuntimeTreeState>()
    }

    fn state(&self) -> iced::advanced::widget::tree::State {
        iced::advanced::widget::tree::State::new(IcedRuntimeTreeState {
            id: self.widget.id(),
            slot: self.runtime_slot.clone(),
            presentation: None,
            text_edit_trees: Vec::new(),
            text_editor_trees: Vec::new(),
            scroll_region_trees: Vec::new(),
            hovered_region: None,
            pressed_region: None,
            indicator_drag: None,
            focused_region: None,
            published_preedit_style: None,
            layout_pass: 0,
        })
    }

    fn children(&self) -> Vec<iced::advanced::widget::Tree> {
        iced_runtime_child_trees::<W, Theme, Renderer>(
            self.widget,
            self.external,
            self.local,
            self.frame_seed.as_ref(),
            None,
            None,
        )
    }

    fn diff(&self, tree: &mut iced::advanced::widget::Tree) {
        let topology = self.widget.topology(self.external);
        let id = topology.id.clone();
        let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
        if state.id != id || state.slot != self.runtime_slot {
            state.id = id;
            state.slot = self.runtime_slot.clone();
            state.presentation = None;
            state.text_edit_trees.clear();
            state.text_editor_trees.clear();
            state.scroll_region_trees.clear();
            state.hovered_region = None;
            state.pressed_region = None;
            state.focused_region = None;
            state.layout_pass = 0;
        }
        let previous_child_context = state.presentation.as_ref().map(|presentation| {
            (
                presentation.frame.clone(),
                root_child_placements_excluding_native_scroll(presentation),
            )
        });
        reconcile_iced_runtime_child_trees::<W, Theme, Renderer>(
            self.widget,
            self.external,
            self.local,
            &mut tree.children,
            self.frame_seed.as_ref(),
            None,
            previous_child_context
                .as_ref()
                .map(|(frame, placements)| (frame, placements.as_ref())),
        );
    }

    fn size(&self) -> iced::Size<iced::Length> {
        iced::Size {
            width: self.width,
            height: self.height,
        }
    }

    fn layout(
        &mut self,
        tree: &mut iced::advanced::widget::Tree,
        renderer: &Renderer,
        limits: &iced::advanced::layout::Limits,
    ) -> iced::advanced::layout::Node {
        let input = iced_layout_input_from_limits(limits);
        let root_placements = {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            state.id = self.widget.id();
            if !state.presentation.as_ref().is_some_and(|presentation| {
                iced_presentation_cache_matches(
                    presentation,
                    &input,
                    self.frame_seed.as_ref(),
                    None,
                    &state.id,
                    self.runtime_slot.as_ref(),
                    Point { x: 0.0, y: 0.0 },
                )
            }) {
                state.layout_pass = state.layout_pass.saturating_add(1);
                self.push_layout_intent(&input);
                state.presentation = Some(iced_presentation_for_widget_with_root_origin(
                    self.widget,
                    self.external,
                    self.local,
                    input,
                    self.frame_seed.as_ref(),
                    state.layout_pass,
                    self.runtime_slot.as_ref(),
                    Point { x: 0.0, y: 0.0 },
                ));
            }
            state
                .presentation
                .as_ref()
                .map(root_child_placements_excluding_native_scroll)
                .unwrap_or_default()
        };
        let (child_frame, root_origin, dispatch_context) = {
            let presentation = tree
                .state
                .downcast_ref::<IcedRuntimeTreeState>()
                .presentation
                .as_ref()
                .expect("runtime layout must create presentation before child layout");
            (
                presentation.frame.clone(),
                presentation.root_origin,
                presentation.dispatch_context.clone(),
            )
        };
        let mut child_nodes = layout_iced_runtime_children::<W, Theme, Renderer>(
            self.widget,
            self.external,
            self.local,
            &mut tree.children,
            renderer,
            root_placements.as_ref(),
            &child_frame,
            self.frame_seed.as_ref(),
            None,
            root_origin,
            Some(&dispatch_context),
        );
        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_mut()
                .expect("runtime layout must create presentation before child occlusion merge");
            merge_child_explicit_layer_occlusions_into_presentation(
                self.widget,
                self.external,
                self.local,
                presentation,
                root_placements.as_ref(),
                &tree.children,
            );
        }
        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime layout must create presentation before scroll layout");
            child_nodes.extend(layout_iced_scroll_regions::<W, Theme, Renderer>(
                &mut state.scroll_region_trees,
                self.widget,
                self.external,
                self.local,
                presentation,
                renderer,
                self.frame_seed.as_ref(),
                None,
            ));
        }
        let (text_input_regions, text_editor_regions) = {
            let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
            let presentation = state.presentation.as_ref();
            (
                presentation
                    .map(text_input_focus_regions)
                    .unwrap_or_default(),
                presentation
                    .map(text_editor_focus_regions)
                    .unwrap_or_default(),
            )
        };
        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            if let Some(presentation) = state.presentation.as_ref() {
                child_nodes.extend(layout_iced_text_editor_regions::<
                    W::AppMessage,
                    Theme,
                    Renderer,
                >(
                    &mut state.text_editor_trees,
                    renderer,
                    presentation,
                    text_editor_regions.as_ref(),
                ));
                child_nodes.extend(layout_iced_text_input_regions::<
                    W::AppMessage,
                    Theme,
                    Renderer,
                >(
                    &mut state.text_edit_trees,
                    renderer,
                    presentation,
                    text_input_regions.as_ref(),
                ));
            }
        }
        {
            // Refresh this presentation's flattened descendant hit regions from
            // the current mounted child presentations (already laid out above,
            // including native-scroll subtrees). This keeps a reused composite
            // presentation's `ViewRootLocal` dispatch geometry current after an
            // intra-child drag without a full composite rebuild.
            let mut child_hit_regions = std::collections::HashMap::new();
            {
                let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
                for scroll_tree in &state.scroll_region_trees {
                    collect_descendant_runtime_hit_regions(scroll_tree, &mut child_hit_regions);
                }
            }
            for child in &tree.children {
                collect_descendant_runtime_hit_regions(child, &mut child_hit_regions);
            }
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            if let Some(presentation) = state.presentation.as_mut() {
                refresh_composite_child_hit_regions(presentation, &child_hit_regions);
            }
        }
        let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
        let presentation = state
            .presentation
            .as_ref()
            .expect("runtime layout must create a presentation before building a node");
        let node = iced_node_for_presentation_with_children(
            self.width,
            self.height,
            limits,
            presentation,
            child_nodes,
        );
        node
    }

    fn operate(
        &mut self,
        tree: &mut iced::advanced::widget::Tree,
        layout: iced::advanced::Layout<'_>,
        renderer: &Renderer,
        operation: &mut dyn iced::advanced::widget::Operation,
    ) {
        let (
            root_placements,
            text_input_regions,
            text_editor_regions,
            frame,
            root_origin,
            dispatch_context,
        ) = {
            let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime operate must have presentation before child operation");
            (
                root_child_placements_excluding_native_scroll(presentation),
                text_input_focus_regions(presentation),
                text_editor_focus_regions(presentation),
                presentation.frame.clone(),
                presentation.root_origin,
                presentation.dispatch_context.clone(),
            )
        };
        let text_region_count = text_input_regions.len() + text_editor_regions.len();
        operate_iced_root_container(&self.widget.id(), layout, operation);
        operation.traverse(&mut |operation| {
            operate_iced_runtime_children::<W, Theme, Renderer>(
                self.widget,
                self.external,
                self.local,
                &mut tree.children,
                layout,
                renderer,
                operation,
                root_placements.as_ref(),
                &frame,
                self.frame_seed.as_ref(),
                None,
                root_origin,
                Some(&dispatch_context),
            );
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            if let Some(presentation) = state.presentation.as_ref() {
                operate_iced_scroll_regions::<W, Theme, Renderer>(
                    &mut state.scroll_region_trees,
                    self.widget,
                    self.external,
                    self.local,
                    presentation,
                    layout,
                    renderer,
                    operation,
                    text_region_count,
                    self.frame_seed.as_ref(),
                    None,
                );
            }
            if let Some(presentation) = state.presentation.as_ref() {
                operate_iced_text_editor_regions::<W::AppMessage, Theme, Renderer>(
                    &mut state.text_editor_trees,
                    presentation,
                    text_editor_regions.as_ref(),
                    text_input_regions.len(),
                    layout,
                    renderer,
                    operation,
                );
            }
            if let Some(presentation) = state.presentation.as_ref() {
                operate_iced_text_input_regions::<W::AppMessage, Theme, Renderer>(
                    &mut state.text_edit_trees,
                    presentation,
                    text_input_regions.as_ref(),
                    layout,
                    renderer,
                    operation,
                );
            }
        });
    }

    fn update(
        &mut self,
        tree: &mut iced::advanced::widget::Tree,
        event: &iced::Event,
        layout: iced::advanced::Layout<'_>,
        cursor: iced::advanced::mouse::Cursor,
        renderer: &Renderer,
        clipboard: &mut dyn iced::advanced::Clipboard,
        shell: &mut iced::advanced::Shell<'_, SlipwayIcedRuntimeMessage>,
        viewport: &iced::Rectangle,
    ) {
        if shell.is_event_captured() {
            return;
        }

        let (
            root_placements,
            text_input_regions,
            text_editor_regions,
            frame,
            root_origin,
            dispatch_context,
        ) = {
            let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime update must have presentation before child update");
            (
                root_child_placements_excluding_native_scroll(presentation),
                text_input_focus_regions(presentation),
                text_editor_focus_regions(presentation),
                presentation.frame.clone(),
                presentation.root_origin,
                presentation.dispatch_context.clone(),
            )
        };
        let text_region_count = text_input_regions.len() + text_editor_regions.len();

        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime update must have presentation before text editor update");
            update_iced_text_editor_regions::<W::AppMessage, Theme, Renderer>(
                &mut state.text_editor_trees,
                presentation,
                text_editor_regions.as_ref(),
                text_input_regions.len(),
                event,
                layout,
                cursor,
                renderer,
                clipboard,
                shell,
                viewport,
                &mut state.published_preedit_style,
            );
        }

        if shell.is_event_captured() {
            return;
        }

        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime update must have presentation before text input update");
            update_iced_text_input_regions::<W::AppMessage, Theme, Renderer>(
                &mut state.text_edit_trees,
                presentation,
                text_input_regions.as_ref(),
                event,
                layout,
                cursor,
                renderer,
                clipboard,
                shell,
                viewport,
                &mut state.published_preedit_style,
            );
        }

        if shell.is_event_captured() {
            return;
        }

        update_iced_runtime_children::<W, Theme, Renderer>(
            self.widget,
            self.external,
            self.local,
            &mut tree.children,
            event,
            layout,
            cursor,
            renderer,
            clipboard,
            shell,
            viewport,
            root_placements.as_ref(),
            &frame,
            self.frame_seed.as_ref(),
            None,
            root_origin,
            Some(&dispatch_context),
        );

        if shell.is_event_captured() {
            return;
        }

        {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            let presentation = state
                .presentation
                .as_ref()
                .expect("runtime update must have presentation before scroll update");
            update_iced_scroll_regions::<W, Theme, Renderer>(
                &mut state.scroll_region_trees,
                self.widget,
                self.external,
                self.local,
                presentation,
                event,
                layout,
                cursor,
                renderer,
                clipboard,
                shell,
                viewport,
                text_region_count,
                self.frame_seed.as_ref(),
                None,
            );
        }

        if shell.is_event_captured() {
            return;
        }

        let routed = {
            let state = tree.state.downcast_mut::<IcedRuntimeTreeState>();
            route_iced_event_for_tree_state(event, layout.bounds(), cursor, state)
        };
        let Some(routed) = routed else {
            return;
        };

        publish_iced_routed_input(shell, routed);
    }

    fn draw(
        &self,
        tree: &iced::advanced::widget::Tree,
        renderer: &mut Renderer,
        _theme: &Theme,
        style: &iced::advanced::renderer::Style,
        layout: iced::advanced::Layout<'_>,
        cursor: iced::advanced::mouse::Cursor,
        viewport: &iced::Rectangle,
    ) {
        let runtime_widget = SlipwayIcedRuntimeWidget {
            widget: self.widget,
            external: self.external,
            local: self.local,
            runtime_slot: self.runtime_slot.clone(),
            width: self.width,
            height: self.height,
            presented_viewport_sink: None,
            frame_seed: self.frame_seed.clone(),
            dirty_scopes: None,
            root_origin: Point { x: 0.0, y: 0.0 },
            dispatch_context: None,
        };
        with_iced_surface_global_paint_queue(renderer, |renderer| {
            draw_iced_runtime_widget_local::<W, Theme, Renderer>(
                &runtime_widget,
                tree,
                renderer,
                _theme,
                style,
                layout,
                cursor,
                viewport,
            );
        });
    }

    fn mouse_interaction(
        &self,
        tree: &iced::advanced::widget::Tree,
        layout: iced::advanced::Layout<'_>,
        cursor: iced::advanced::mouse::Cursor,
        viewport: &iced::Rectangle,
        renderer: &Renderer,
    ) -> iced::advanced::mouse::Interaction {
        let state = tree.state.downcast_ref::<IcedRuntimeTreeState>();
        let root_placements = state
            .presentation
            .as_ref()
            .map(root_child_placements_excluding_native_scroll)
            .unwrap_or_default();
        if let Some(presentation) = state.presentation.as_ref() {
            let child_interaction = iced_runtime_children_mouse_interaction::<W, Theme, Renderer>(
                self.widget,
                self.external,
                self.local,
                &tree.children,
                layout,
                cursor,
                viewport,
                renderer,
                root_placements.as_ref(),
                &presentation.frame,
                self.frame_seed.as_ref(),
                None,
                presentation.root_origin,
                Some(&presentation.dispatch_context),
            );
            if child_interaction != iced::advanced::mouse::Interaction::None {
                return child_interaction;
            }
        }
        let text_input_regions = state
            .presentation
            .as_ref()
            .map(text_input_focus_regions)
            .unwrap_or_default();
        let text_editor_regions = state
            .presentation
            .as_ref()
            .map(text_editor_focus_regions)
            .unwrap_or_default();
        let text_region_count = text_input_regions.len() + text_editor_regions.len();
        if let Some(presentation) = state.presentation.as_ref() {
            let scroll_interaction = iced_scroll_regions_mouse_interaction::<W, Theme, Renderer>(
                &state.scroll_region_trees,
                self.widget,
                self.external,
                self.local,
                presentation,
                layout,
                cursor,
                viewport,
                renderer,
                text_region_count,
                self.frame_seed.as_ref(),
                None,
            );
            if scroll_interaction != iced::advanced::mouse::Interaction::None {
                return scroll_interaction;
            }
        }
        let text_editor_interaction = state.presentation.as_ref().map_or(
            iced::advanced::mouse::Interaction::None,
            |presentation| {
                iced_text_editor_regions_mouse_interaction::<W::AppMessage, Theme, Renderer>(
                    &state.text_editor_trees,
                    presentation,
                    text_editor_regions.as_ref(),
                    text_input_regions.len(),
                    layout,
                    cursor,
                    viewport,
                    renderer,
                )
            },
        );
        if text_editor_interaction != iced::advanced::mouse::Interaction::None {
            return text_editor_interaction;
        }
        let text_interaction = state.presentation.as_ref().map_or(
            iced::advanced::mouse::Interaction::None,
            |presentation| {
                iced_text_input_regions_mouse_interaction::<W::AppMessage, Theme, Renderer>(
                    &state.text_edit_trees,
                    presentation,
                    text_input_regions.as_ref(),
                    layout,
                    cursor,
                    viewport,
                    renderer,
                )
            },
        );
        if text_interaction != iced::advanced::mouse::Interaction::None {
            return text_interaction;
        }
        mouse_interaction_for_presentation(layout.bounds(), cursor, state.presentation.as_ref())
    }

    fn overlay<'b>(
        &'b mut self,
        _tree: &'b mut iced::advanced::widget::Tree,
        _layout: iced::advanced::Layout<'b>,
        _renderer: &Renderer,
        _viewport: &iced::Rectangle,
        _translation: iced::Vector,
    ) -> Option<iced::advanced::overlay::Element<'b, SlipwayIcedRuntimeMessage, Theme, Renderer>>
    {
        // See SlipwayIcedRuntimeWidget::overlay for the current lifecycle gate.
        None
    }
}

impl<'a, W, Theme, Renderer> From<SlipwayIcedWidget<'a, W>>
    for iced::Element<'a, W::AppMessage, Theme, Renderer>
where
    W: SlipwayIcedBackendWidget + 'a,
    W::ExternalState: 'a,
    W::LocalState: Clone + 'static,
    W::AppMessage: 'a,
    Renderer: iced::advanced::text::Renderer<Font = iced::Font>
        + iced::advanced::graphics::geometry::Renderer
        + 'a + 'static,
{
    fn from(widget: SlipwayIcedWidget<'a, W>) -> Self {
        iced::Element::new(widget)
    }
}

impl<'a, W, Theme, Renderer> From<SlipwayIcedLayoutIntentWidget<'a, W>>
    for iced::Element<'a, W::AppMessage, Theme, Renderer>
where
    W: SlipwayIcedLayoutIntentBackendWidget + 'a,
    W::ExternalState: 'a,
    W::LocalState: Clone + 'static,
    W::AppMessage: 'a,
    Renderer: iced::advanced::text::Renderer<Font = iced::Font>
        + iced::advanced::graphics::geometry::Renderer
        + 'a + 'static,
{
    fn from(widget: SlipwayIcedLayoutIntentWidget<'a, W>) -> Self {
        iced::Element::new(widget)
    }
}

impl<W, Theme, Renderer> iced::advanced::Widget<W::AppMessage, Theme, Renderer>
    for SlipwayIcedWidget<'_, W>
where
    W: SlipwayIcedBackendWidget,
    W::LocalState: Clone + 'static,
    Renderer: iced::advanced::text::Renderer<Font = iced::Font>
        + iced::advanced::graphics::geometry::Renderer
        + 'static,
{
    fn tag(&self) -> iced::advanced::widget::tree::Tag {
        iced::advanced::widget::tree::Tag::of::<IcedTreeState<W::LocalState>>()
    }

    fn state(&self) -> iced::advanced::widget::tree::State {
        assert_iced_standalone_no_topology_children(self.widget, self.external);
        iced::advanced::widget::tree::State::new(IcedTreeState {
            id: self.widget.id(),
            local: self.widget.initial_local_state(),
            presentation: None,
            hovered_region: None,
            pressed_region: None,
            indicator_drag: None,
            focused_region: None,
            layout_pass: 0,
        })
    }

    fn children(&self) -> Vec<iced::advanced::widget::Tree> {
        assert_iced_standalone_no_topology_children(self.widget, self.external);
        Vec::new()
    }

    fn diff(&self, tree: &mut iced::advanced::widget::Tree) {
        assert_iced_standalone_no_topology_children(self.widget, self.external);
        let topology = self.widget.topology(self.external);
        let id = topology.id.clone();
        let state = tree.state.downcast_mut::<IcedTreeState<W::LocalState>>();
        if state.id != id {
            state.id = id;
            state.local = self.widget.initial_local_state();
            state.presentation = None;
            state.hovered_region = None;
            state.pressed_region = None;
            state.focused_region = None;
            state.layout_pass = 0;
        }
        tree.children.clear();
    }

    fn size(&self) -> iced::Size<iced::Length> {
        iced::Size {
            width: self.width,
            height: self.height,
        }
    }

    fn layout(
        &mut self,
        tree: &mut iced::advanced::widget::Tree,
        _renderer: &Renderer,
        limits: &iced::advanced::layout::Limits,
    ) -> iced::advanced::layout::Node {
        assert_iced_standalone_no_topology_children(self.widget, self.external);
        let state = tree.state.downcast_mut::<IcedTreeState<W::LocalState>>();
        state.layout_pass = state.layout_pass.saturating_add(1);

        let input = iced_layout_input_from_limits(limits);
        let presentation = iced_presentation_for_widget(
            self.widget,
            self.external,
            &state.local,
            input,
            None,
            state.layout_pass,
            None,
        );
        assert_iced_standalone_no_layout_children(&state.id, &presentation.layout);
        let node = iced_node_for_presentation(self.width, self.height, limits, &presentation);
        state.presentation = Some(presentation);
        node
    }

    fn operate(
        &mut self,
        _tree: &mut iced::advanced::widget::Tree,
        layout: iced::advanced::Layout<'_>,
        _renderer: &Renderer,
        operation: &mut dyn iced::advanced::widget::Operation,
    ) {
        operate_iced_root_container(&self.widget.id(), layout, operation);
        operation.traverse(&mut |_operation| {});
    }

    fn update(
        &mut self,
        tree: &mut iced::advanced::widget::Tree,
        event: &iced::Event,
        layout: iced::advanced::Layout<'_>,
        cursor: iced::advanced::mouse::Cursor,
        _renderer: &Renderer,
        _clipboard: &mut dyn iced::advanced::Clipboard,
        shell: &mut iced::advanced::Shell<'_, W::AppMessage>,
        _viewport: &iced::Rectangle,
    ) {
        if shell.is_event_captured() {
            return;
        }

        let state = tree.state.downcast_mut::<IcedTreeState<W::LocalState>>();
        let Some(routed) = route_iced_event(
            event,
            layout.bounds(),
            cursor,
            state.presentation.as_ref(),
            &mut state.hovered_region,
            &mut state.pressed_region,
            &mut state.indicator_drag,
            &mut state.focused_region,
        ) else {
            return;
        };

        let Some(input) = routed.input else {
            if routed.request_redraw {
                shell.request_redraw();
            }
            return;
        };

        let event = input.event.clone();
        let declaration =
            slipway_core::declared_event_handling(self.widget, self.external, &state.local, &event);
        if !declaration.disposition.final_disposition.handled {
            return;
        }
        let raw_outcome = self
            .widget
            .handle_event(self.external, &mut state.local, event);
        let outcome =
            slipway_core::apply_physical_event_handling_declaration(declaration, raw_outcome);
        let handled = outcome.handled || !outcome.emitted_messages.is_empty();

        for message in outcome.emitted_messages {
            shell.publish(message.message);
        }

        if handled {
            shell.capture_event();
        }
        if handled || routed.request_redraw {
            shell.request_redraw();
        }
    }

    fn draw(
        &self,
        tree: &iced::advanced::widget::Tree,
        renderer: &mut Renderer,
        _theme: &Theme,
        _style: &iced::advanced::renderer::Style,
        layout: iced::advanced::Layout<'_>,
        _cursor: iced::advanced::mouse::Cursor,
        _viewport: &iced::Rectangle,
    ) {
        let state = tree.state.downcast_ref::<IcedTreeState<W::LocalState>>();
        let bounds = layout.bounds();
        let Some(presentation) = state.presentation.as_ref() else {
            return;
        };

        draw_iced_standalone_presentation(renderer, bounds.position(), presentation);
    }

    fn mouse_interaction(
        &self,
        tree: &iced::advanced::widget::Tree,
        layout: iced::advanced::Layout<'_>,
        cursor: iced::advanced::mouse::Cursor,
        _viewport: &iced::Rectangle,
        _renderer: &Renderer,
    ) -> iced::advanced::mouse::Interaction {
        let state = tree.state.downcast_ref::<IcedTreeState<W::LocalState>>();
        mouse_interaction_for_presentation(layout.bounds(), cursor, state.presentation.as_ref())
    }
}

impl<W, Theme, Renderer> iced::advanced::Widget<W::AppMessage, Theme, Renderer>
    for SlipwayIcedLayoutIntentWidget<'_, W>
where
    W: SlipwayIcedLayoutIntentBackendWidget,
    W::LocalState: Clone + 'static,
    Renderer: iced::advanced::text::Renderer<Font = iced::Font>
        + iced::advanced::graphics::geometry::Renderer
        + 'static,
{
    fn tag(&self) -> iced::advanced::widget::tree::Tag {
        iced::advanced::widget::tree::Tag::of::<IcedTreeState<W::LocalState>>()
    }

    fn state(&self) -> iced::advanced::widget::tree::State {
        assert_iced_standalone_no_topology_children(self.widget, self.external);
        iced::advanced::widget::tree::State::new(IcedTreeState {
            id: self.widget.id(),
            local: self.widget.initial_local_state(),
            presentation: None,
            hovered_region: None,
            pressed_region: None,
            indicator_drag: None,
            focused_region: None,
            layout_pass: 0,
        })
    }

    fn children(&self) -> Vec<iced::advanced::widget::Tree> {
        assert_iced_standalone_no_topology_children(self.widget, self.external);
        Vec::new()
    }

    fn diff(&self, tree: &mut iced::advanced::widget::Tree) {
        assert_iced_standalone_no_topology_children(self.widget, self.external);
        let topology = self.widget.topology(self.external);
        let id = topology.id.clone();
        let state = tree.state.downcast_mut::<IcedTreeState<W::LocalState>>();
        if state.id != id {
            state.id = id;
            state.local = self.widget.initial_local_state();
            state.presentation = None;
            state.hovered_region = None;
            state.pressed_region = None;
            state.focused_region = None;
            state.layout_pass = 0;
        }
        tree.children.clear();
    }

    fn size(&self) -> iced::Size<iced::Length> {
        iced::Size {
            width: self.width,
            height: self.height,
        }
    }

    fn layout(
        &mut self,
        tree: &mut iced::advanced::widget::Tree,
        _renderer: &Renderer,
        limits: &iced::advanced::layout::Limits,
    ) -> iced::advanced::layout::Node {
        assert_iced_standalone_no_topology_children(self.widget, self.external);
        let state = tree.state.downcast_mut::<IcedTreeState<W::LocalState>>();
        state.layout_pass = state.layout_pass.saturating_add(1);

        let input = iced_layout_input_from_limits(limits);
        self.push_layout_intent(&state.local, &input);
        let presentation = iced_presentation_for_widget(
            self.widget,
            self.external,
            &state.local,
            input,
            None,
            state.layout_pass,
            None,
        );
        assert_iced_standalone_no_layout_children(&state.id, &presentation.layout);
        let node = iced_node_for_presentation(self.width, self.height, limits, &presentation);
        state.presentation = Some(presentation);
        node
    }

    fn operate(
        &mut self,
        _tree: &mut iced::advanced::widget::Tree,
        layout: iced::advanced::Layout<'_>,
        _renderer: &Renderer,
        operation: &mut dyn iced::advanced::widget::Operation,
    ) {
        operate_iced_root_container(&self.widget.id(), layout, operation);
        operation.traverse(&mut |_operation| {});
    }

    fn update(
        &mut self,
        tree: &mut iced::advanced::widget::Tree,
        event: &iced::Event,
        layout: iced::advanced::Layout<'_>,
        cursor: iced::advanced::mouse::Cursor,
        _renderer: &Renderer,
        _clipboard: &mut dyn iced::advanced::Clipboard,
        shell: &mut iced::advanced::Shell<'_, W::AppMessage>,
        _viewport: &iced::Rectangle,
    ) {
        if shell.is_event_captured() {
            return;
        }

        let state = tree.state.downcast_mut::<IcedTreeState<W::LocalState>>();
        let Some(routed) = route_iced_event(
            event,
            layout.bounds(),
            cursor,
            state.presentation.as_ref(),
            &mut state.hovered_region,
            &mut state.pressed_region,
            &mut state.indicator_drag,
            &mut state.focused_region,
        ) else {
            return;
        };

        let Some(input) = routed.input else {
            if routed.request_redraw {
                shell.request_redraw();
            }
            return;
        };

        let event = input.event.clone();
        let declaration =
            slipway_core::declared_event_handling(self.widget, self.external, &state.local, &event);
        if !declaration.disposition.final_disposition.handled {
            return;
        }
        let raw_outcome = self
            .widget
            .handle_event(self.external, &mut state.local, event);
        let outcome =
            slipway_core::apply_physical_event_handling_declaration(declaration, raw_outcome);
        let handled = outcome.handled || !outcome.emitted_messages.is_empty();

        for message in outcome.emitted_messages {
            shell.publish(message.message);
        }

        if handled {
            shell.capture_event();
        }
        if handled || routed.request_redraw {
            shell.request_redraw();
        }
    }

    fn draw(
        &self,
        tree: &iced::advanced::widget::Tree,
        renderer: &mut Renderer,
        _theme: &Theme,
        _style: &iced::advanced::renderer::Style,
        layout: iced::advanced::Layout<'_>,
        _cursor: iced::advanced::mouse::Cursor,
        _viewport: &iced::Rectangle,
    ) {
        let state = tree.state.downcast_ref::<IcedTreeState<W::LocalState>>();
        let bounds = layout.bounds();
        let Some(presentation) = state.presentation.as_ref() else {
            return;
        };

        draw_iced_standalone_presentation(renderer, bounds.position(), presentation);
    }

    fn mouse_interaction(
        &self,
        tree: &iced::advanced::widget::Tree,
        layout: iced::advanced::Layout<'_>,
        cursor: iced::advanced::mouse::Cursor,
        _viewport: &iced::Rectangle,
        _renderer: &Renderer,
    ) -> iced::advanced::mouse::Interaction {
        let state = tree.state.downcast_ref::<IcedTreeState<W::LocalState>>();
        mouse_interaction_for_presentation(layout.bounds(), cursor, state.presentation.as_ref())
    }
}

fn route_iced_event_for_tree_state(
    event: &iced::Event,
    layout_bounds: iced::Rectangle,
    cursor: iced::advanced::mouse::Cursor,
    state: &mut IcedRuntimeTreeState,
) -> Option<IcedRoutedInput> {
    let mut hovered = state.hovered_region.clone();
    let mut pressed = state.pressed_region.clone();
    let mut indicator_drag = state.indicator_drag.clone();
    let mut focused = state.focused_region.clone();
    let routed = route_iced_event(
        event,
        layout_bounds,
        cursor,
        state.presentation.as_ref(),
        &mut hovered,
        &mut pressed,
        &mut indicator_drag,
        &mut focused,
    );
    state.hovered_region = hovered;
    state.pressed_region = pressed;
    state.indicator_drag = indicator_drag;
    state.focused_region = focused;
    routed
}

fn publish_iced_routed_input(
    shell: &mut iced::advanced::Shell<'_, SlipwayIcedRuntimeMessage>,
    routed: IcedRoutedInput,
) {
    if let Some(input) = routed.input {
        shell.publish(SlipwayIcedRuntimeMessage::BackendInput(input));
    }
    if let Some(refusal) = routed.refusal {
        shell.publish(SlipwayIcedRuntimeMessage::DispatchRefusal(refusal));
    }

    if routed.capture_event {
        shell.capture_event();
    }
    if routed.request_redraw {
        shell.request_redraw();
    }
}

fn route_iced_event(
    event: &iced::Event,
    layout_bounds: iced::Rectangle,
    cursor: iced::advanced::mouse::Cursor,
    presentation: Option<&IcedPresentationState>,
    hovered_region: &mut Option<slipway_core::PresentationRegionId>,
    pressed_region: &mut Option<IcedPressedPointerCapture>,
    indicator_drag: &mut Option<IcedIndicatorDragState>,
    focused_region: &mut Option<slipway_core::PresentationRegionId>,
) -> Option<IcedRoutedInput> {
    let presentation = presentation?;
    let previous_hovered_region = hovered_region.clone();
    let pointer_captured = pressed_region.is_some() || indicator_drag.is_some();
    let hover_changed = if pointer_captured {
        false
    } else {
        sync_hover_region(presentation, layout_bounds, cursor, hovered_region)
    };

    match event {
        iced::Event::Mouse(iced::mouse::Event::CursorMoved { position }) => {
            let position = cursor.position().unwrap_or(*position);
            let input_points = iced_input_root_local_points(presentation, layout_bounds, position);
            // Active synthetic-indicator drag: the captured thumb follows
            // the pointer; every move synthesizes a declared Scroll event
            // (the same machinery as the native on_scroll sync).
            if indicator_drag.is_some() {
                let routed = indicator_drag.as_ref().and_then(|drag| {
                    iced_indicator_drag_scroll_input(presentation, drag, input_points.visual.y)
                });
                if routed.is_none() {
                    // The region disappeared from the view: drop the drag.
                    *indicator_drag = None;
                }
                return Some(routed.unwrap_or(IcedRoutedInput {
                    input: None,
                    capture_event: true,
                    request_redraw: true,
                    refusal: None,
                }));
            }
            if let Some(capture_state) = pressed_region.as_ref()
                && let Some(region) = hit_region_by_id(presentation, &capture_state.region_id)
            {
                let capture =
                    pointer_capture_for_region(region, slipway_core::PointerEventKind::Move, true);
                if capture {
                    let capture_layout_bounds =
                        capture_state.layout_bounds_for_capture(layout_bounds);
                    let capture_points =
                        iced_input_root_local_points(presentation, capture_layout_bounds, position);
                    let root_local_position = hit_region_root_local_position_for_input(
                        presentation,
                        region,
                        capture_points,
                    );
                    return Some(captured_pointer_event_for_hit_region_with_details_at_root(
                        region,
                        presentation,
                        root_local_position,
                        slipway_core::PointerEventKind::Move,
                        None,
                        pointer_details(capture_state.button),
                        true,
                        true,
                    ));
                }
            }

            if paint_occlusion_at_input_points(presentation, input_points).is_some()
                && hit_region_at_input_points(presentation, input_points).is_none()
            {
                if foreign_dispatch_hit_blocks_local_input(presentation, input_points) {
                    return Some(IcedRoutedInput {
                        input: None,
                        capture_event: false,
                        request_redraw: hover_changed,
                        refusal: None,
                    });
                }
                return Some(IcedRoutedInput {
                    input: None,
                    capture_event: true,
                    request_redraw: hover_changed,
                    refusal: None,
                });
            }

            hover_changed.then_some(IcedRoutedInput {
                input: None,
                capture_event: false,
                request_redraw: true,
                refusal: None,
            })
        }
        iced::Event::Mouse(iced::mouse::Event::CursorEntered) => {
            let Some(position) = cursor.position() else {
                return hover_changed.then_some(IcedRoutedInput {
                    input: None,
                    capture_event: false,
                    request_redraw: true,
                    refusal: None,
                });
            };
            let input_points = iced_input_root_local_points(presentation, layout_bounds, position);
            let Some(resolved) = hit_region_at_input_points(presentation, input_points) else {
                return hover_changed.then_some(IcedRoutedInput {
                    input: None,
                    capture_event: false,
                    request_redraw: true,
                    refusal: None,
                });
            };

            Some(pointer_event_for_hit_region_with_details_at_root(
                resolved.region,
                presentation,
                resolved.root_local_position,
                slipway_core::PointerEventKind::Enter,
                None,
                pointer_details(None),
                false,
                true,
            ))
        }
        iced::Event::Mouse(iced::mouse::Event::CursorLeft) => {
            let previous = previous_hovered_region;
            *hovered_region = None;
            let Some(previous) = previous else {
                return hover_changed.then_some(IcedRoutedInput {
                    input: None,
                    capture_event: false,
                    request_redraw: true,
                    refusal: None,
                });
            };
            let Some(region) = hit_region_by_id(presentation, &previous) else {
                return Some(IcedRoutedInput {
                    input: None,
                    capture_event: false,
                    request_redraw: true,
                    refusal: None,
                });
            };
            let region_rect = region_root_local_rect(
                presentation,
                &region.target,
                region.address.as_ref(),
                region.bounds.into_rect(),
            );
            let position = iced::Point::new(
                layout_bounds.x + region_rect.origin.x,
                layout_bounds.y + region_rect.origin.y,
            );

            Some(pointer_event_for_hit_region(
                region,
                presentation,
                layout_bounds,
                position,
                slipway_core::PointerEventKind::Leave,
                None,
                false,
                true,
            ))
        }
        iced::Event::Mouse(iced::mouse::Event::ButtonPressed(button)) => {
            let position = cursor.position()?;
            let input_points = iced_input_root_local_points(presentation, layout_bounds, position);

            // Synthetic-indicator interaction (Step 212): a press on a
            // synthesized track/thumb is claimed by the backend BEFORE
            // authored hit resolution — the indicator paints in front of
            // the authored content it annotates, so its hit surface fronts
            // it too, EXCEPT under an opaque authored layer above the
            // indicator layer's z (the occlusion guard inside the helper:
            // pointer selection agrees with visible stacking). Thumb press
            // -> captured drag; track press -> JUMP-TO-POSITION (the thumb
            // centers on the click and the press keeps dragging from
            // there).
            if *button == iced::mouse::Button::Left
                && let Some((drag, jump)) =
                    iced_indicator_press_interaction(presentation, input_points)
            {
                let routed = jump
                    .and_then(|offset_y| {
                        iced_indicator_scroll_input_for_offset(
                            presentation,
                            &drag.region_id,
                            offset_y,
                        )
                    })
                    .unwrap_or(IcedRoutedInput {
                        input: None,
                        capture_event: true,
                        request_redraw: true,
                        refusal: None,
                    });
                *indicator_drag = Some(drag);
                return Some(routed);
            }

            let focus_changed = focus_region_at_input_points(presentation, input_points)
                .map(|resolved| set_region_id(focused_region, Some(resolved.region.id.clone())))
                .unwrap_or_else(|| set_region_id(focused_region, None));

            if let Some(resolved) = hit_region_at_input_points(presentation, input_points) {
                *pressed_region = Some(IcedPressedPointerCapture::new(
                    resolved.region.id.clone(),
                    layout_bounds,
                    Some(*button),
                ));
                let capture = pointer_capture_for_region(
                    resolved.region,
                    slipway_core::PointerEventKind::Press,
                    true,
                );

                return Some(pointer_event_for_hit_region_with_details_at_root(
                    resolved.region,
                    presentation,
                    resolved.root_local_position,
                    slipway_core::PointerEventKind::Press,
                    Some(pointer_button(*button)),
                    pointer_details(Some(*button)),
                    capture,
                    true,
                ));
            }

            if foreign_dispatch_hit_blocks_local_input(presentation, input_points) {
                return Some(IcedRoutedInput {
                    input: None,
                    capture_event: false,
                    request_redraw: focus_changed || hover_changed,
                    refusal: None,
                });
            }

            if paint_occlusion_at_input_points(presentation, input_points).is_some() {
                return Some(IcedRoutedInput {
                    input: None,
                    capture_event: true,
                    request_redraw: focus_changed || hover_changed,
                    refusal: None,
                });
            }

            let Some(resolved) = focus_region_at_input_points(presentation, input_points) else {
                return (hover_changed || focus_changed).then_some(IcedRoutedInput {
                    input: None,
                    capture_event: false,
                    request_redraw: true,
                    refusal: None,
                });
            };

            Some(pointer_event_for_focus_region_at_root(
                resolved.region,
                presentation,
                resolved.root_local_position,
                slipway_core::PointerEventKind::Press,
                Some(*button),
                true,
                true,
            ))
        }
        iced::Event::Mouse(iced::mouse::Event::ButtonReleased(button)) => {
            // End of a synthetic-indicator drag: consume the release; the
            // declared offset already tracks the last drag move.
            if indicator_drag.take().is_some() {
                return Some(IcedRoutedInput {
                    input: None,
                    capture_event: true,
                    request_redraw: true,
                    refusal: None,
                });
            }
            let position = cursor.position()?;
            let input_points = iced_input_root_local_points(presentation, layout_bounds, position);
            let released_pressed_region = pressed_region.take();
            if let Some(capture_state) = released_pressed_region.as_ref()
                && let Some(region) = hit_region_by_id(presentation, &capture_state.region_id)
                && pointer_capture_for_region(
                    region,
                    slipway_core::PointerEventKind::Release,
                    false,
                )
            {
                let capture_layout_bounds = capture_state.layout_bounds_for_capture(layout_bounds);
                let capture_points =
                    iced_input_root_local_points(presentation, capture_layout_bounds, position);
                let root_local_position =
                    hit_region_root_local_position_for_input(presentation, region, capture_points);
                return Some(captured_pointer_event_for_hit_region_with_details_at_root(
                    region,
                    presentation,
                    root_local_position,
                    slipway_core::PointerEventKind::Release,
                    Some(pointer_button(*button)),
                    pointer_details(Some(*button)),
                    true,
                    true,
                ));
            }
            let hit_region = hit_region_at_input_points(presentation, input_points).or_else(|| {
                released_pressed_region
                    .as_ref()
                    .and_then(|capture| hit_region_by_id(presentation, &capture.region_id))
                    .map(|region| IcedResolvedHitRegion {
                        region,
                        root_local_position: hit_region_root_local_position_for_input(
                            presentation,
                            region,
                            input_points,
                        ),
                    })
            });

            let Some(resolved) = hit_region else {
                if paint_occlusion_at_input_points(presentation, input_points).is_some() {
                    if foreign_dispatch_hit_blocks_local_input(presentation, input_points) {
                        return Some(IcedRoutedInput {
                            input: None,
                            capture_event: false,
                            request_redraw: hover_changed,
                            refusal: None,
                        });
                    }
                    return Some(IcedRoutedInput {
                        input: None,
                        capture_event: true,
                        request_redraw: hover_changed,
                        refusal: None,
                    });
                }
                return hover_changed.then_some(IcedRoutedInput {
                    input: None,
                    capture_event: false,
                    request_redraw: true,
                    refusal: None,
                });
            };
            let capture = released_pressed_region.is_some()
                || pointer_capture_for_region(
                    resolved.region,
                    slipway_core::PointerEventKind::Release,
                    false,
                );

            Some(pointer_event_for_hit_region_with_details_at_root(
                resolved.region,
                presentation,
                resolved.root_local_position,
                slipway_core::PointerEventKind::Release,
                Some(pointer_button(*button)),
                pointer_details(Some(*button)),
                capture,
                released_pressed_region.is_some() || hover_changed,
            ))
        }
        iced::Event::Mouse(iced::mouse::Event::WheelScrolled { delta }) => {
            let position = cursor.position()?;
            let input_points = iced_input_root_local_points(presentation, layout_bounds, position);
            let (delta_x, delta_y) = match delta {
                iced::mouse::ScrollDelta::Lines { x, y } => (*x, *y),
                iced::mouse::ScrollDelta::Pixels { x, y } => (*x, *y),
            };
            let uses_mounted_context = presentation.dispatch_context.position_space
                == IcedDispatchPositionSpace::MountedRootLocal;
            let (dispatch_position, dispatch_position_space) =
                iced_wheel_dispatch_root_local_position(
                    presentation,
                    uses_mounted_context,
                    input_points,
                    delta_x,
                    delta_y,
                );
            // The runtime independently re-resolves wheel dispatch at
            // `evidence.input_position` against the current view's declared
            // scroll regions (`refresh_backend_presented_scroll_input_for_
            // current_view` and `validate_wheel_dispatch_evidence`), whose
            // viewport rects live in un-scrolled root content space. The
            // recorded position must therefore be the resolved dispatch-space
            // point — the point at which that naive re-resolution reproduces
            // this route's consumer choice — never the raw visual window
            // point: under a nonzero native scroll offset the raw point
            // re-resolves to whatever region owns that fixed window band,
            // which live turned a routed child wheel into a state-only root
            // ghost (and the ghost-inflated declared offset then killed the
            // native root scrollable entirely).
            let evidence_position = if uses_mounted_context {
                dispatch_position
            } else {
                iced_evidence_root_local_point(presentation, dispatch_position)
            };
            let dispatch_geometry_index = if uses_mounted_context {
                &presentation.dispatch_context.geometry_index
            } else {
                &presentation.geometry_index
            };
            let dispatch_scroll_regions = if uses_mounted_context {
                Cow::Borrowed(presentation.dispatch_context.scroll_regions.as_ref())
            } else {
                Cow::Borrowed(presentation.scroll_regions.as_slice())
            };
            let (dispatch, evidence) =
                slipway_core::resolve_declared_wheel_dispatch_with_evidence_and_geometry_index(
                    EvidenceSource::backend_presented(ICED_BACKEND_ID, "physical-input"),
                    presentation.frame.clone(),
                    dispatch_geometry_index,
                    dispatch_scroll_regions.as_ref(),
                    dispatch_position,
                    delta_x,
                    delta_y,
                );
            let mut evidence = evidence;
            evidence.input_position = Some(evidence_position);
            evidence.input_position_space = Some(dispatch_position_space);
            let Some(dispatch) = dispatch else {
                // No consumer (dead point / at-limit): retain the
                // already-constructed refusal evidence instead of dropping it
                // (audit finding MF-H3).
                let mut refusal = evidence;
                if front_wheel_blocker_order_at_input_points(presentation, input_points, None)
                    .is_some()
                {
                    refusal.refusal_reason = Some(format!(
                        "{}; a front wheel-blocking paint layer captured the wheel",
                        refusal.refusal_reason.as_deref().unwrap_or(
                            "no enabled scroll region accepted the physical wheel position"
                        )
                    ));
                    return Some(IcedRoutedInput {
                        input: None,
                        capture_event: true,
                        request_redraw: false,
                        refusal: Some(refusal),
                    });
                }
                return Some(IcedRoutedInput {
                    input: None,
                    capture_event: false,
                    request_redraw: false,
                    refusal: Some(refusal),
                });
            };
            if let Some(selected_scroll) = dispatch_scroll_regions
                .iter()
                .find(|scroll| scroll.id == dispatch.selected_region)
                && wheel_blocker_prevents_scroll_dispatch(
                    presentation,
                    input_points,
                    selected_scroll,
                )
            {
                // Blocked wheel: the dispatch resolved but a front
                // wheel-blocking paint layer swallowed it — retain that as a
                // refusal too (MF-H3).
                let mut refusal = evidence;
                refusal.refusal_reason = Some(format!(
                    "declared wheel consumer `{}` is blocked by a front wheel-blocking paint layer",
                    dispatch.selected_region.as_str()
                ));
                return Some(IcedRoutedInput {
                    input: None,
                    capture_event: true,
                    request_redraw: false,
                    refusal: Some(refusal),
                });
            }

            Some(IcedRoutedInput {
                capture_event: dispatch.capture_event,
                request_redraw: dispatch.capture_event,
                refusal: None,
                input: Some(BackendInputEvent::declared(dispatch.input, evidence)),
            })
        }
        iced::Event::InputMethod(iced_core::input_method::Event::Commit(text)) => {
            if text.is_empty() {
                return Some(IcedRoutedInput {
                    input: None,
                    capture_event: false,
                    request_redraw: false,
                    refusal: None,
                });
            }
            if !presentation.can_route_text_edit() {
                return None;
            }
            let focus = focused_focus_region(presentation, focused_region.as_ref())?;
            let selection_before = focus
                .text_edit
                .as_ref()
                .and_then(|text_edit| text_edit.selection.selection.clone());
            let event = InputEvent::TextEdit(slipway_core::TextEditEvent {
                target: focus_target(focus),
                target_slot: focus.address.clone(),
                kind: TextEditKind::InsertText,
                text: Some(text.clone()),
                selection_before,
                selection_after: None,
            });
            Some(IcedRoutedInput {
                input: Some(backend_focus_input_event(
                    presentation,
                    focus,
                    DeclaredEventDispatchKind::Text,
                    None,
                    event,
                )),
                capture_event: true,
                request_redraw: true,
                refusal: None,
            })
        }
        iced::Event::Touch(iced::touch::Event::FingerPressed { id, position }) => {
            let Some(region) = hit_region_at_point(presentation, layout_bounds, *position) else {
                return hover_changed.then_some(IcedRoutedInput {
                    input: None,
                    capture_event: false,
                    request_redraw: true,
                    refusal: None,
                });
            };
            *pressed_region = Some(IcedPressedPointerCapture::new(
                region.id.clone(),
                layout_bounds,
                None,
            ));
            let capture =
                pointer_capture_for_region(region, slipway_core::PointerEventKind::Press, true);

            Some(pointer_event_for_hit_region_with_details(
                region,
                presentation,
                layout_bounds,
                *position,
                slipway_core::PointerEventKind::Press,
                None,
                touch_pointer_details(*id, true),
                capture,
                true,
            ))
        }
        iced::Event::Touch(iced::touch::Event::FingerMoved { id, position }) => {
            if let Some(capture_state) = pressed_region.as_ref()
                && let Some(region) = hit_region_by_id(presentation, &capture_state.region_id)
            {
                let capture =
                    pointer_capture_for_region(region, slipway_core::PointerEventKind::Move, true);
                if capture {
                    let capture_layout_bounds =
                        capture_state.layout_bounds_for_capture(layout_bounds);
                    return Some(captured_pointer_event_for_hit_region_with_details(
                        region,
                        presentation,
                        capture_layout_bounds,
                        *position,
                        slipway_core::PointerEventKind::Move,
                        None,
                        touch_pointer_details(*id, true),
                        true,
                        true,
                    ));
                }
            }
            let Some(region) = hit_region_at_point(presentation, layout_bounds, *position) else {
                return hover_changed.then_some(IcedRoutedInput {
                    input: None,
                    capture_event: false,
                    request_redraw: true,
                    refusal: None,
                });
            };

            Some(pointer_event_for_hit_region_with_details(
                region,
                presentation,
                layout_bounds,
                *position,
                slipway_core::PointerEventKind::Move,
                None,
                touch_pointer_details(*id, true),
                false,
                hover_changed,
            ))
        }
        iced::Event::Touch(iced::touch::Event::FingerLifted { id, position }) => {
            let released_pressed_region = pressed_region.take();
            if let Some(capture_state) = released_pressed_region.as_ref()
                && let Some(region) = hit_region_by_id(presentation, &capture_state.region_id)
                && pointer_capture_for_region(
                    region,
                    slipway_core::PointerEventKind::Release,
                    false,
                )
            {
                let capture_layout_bounds = capture_state.layout_bounds_for_capture(layout_bounds);
                return Some(captured_pointer_event_for_hit_region_with_details(
                    region,
                    presentation,
                    capture_layout_bounds,
                    *position,
                    slipway_core::PointerEventKind::Release,
                    None,
                    touch_pointer_details(*id, false),
                    true,
                    true,
                ));
            }
            let region =
                hit_region_at_point(presentation, layout_bounds, *position).or_else(|| {
                    released_pressed_region
                        .as_ref()
                        .and_then(|capture| hit_region_by_id(presentation, &capture.region_id))
                })?;

            Some(pointer_event_for_hit_region_with_details(
                region,
                presentation,
                layout_bounds,
                *position,
                slipway_core::PointerEventKind::Release,
                None,
                touch_pointer_details(*id, false),
                released_pressed_region.is_some(),
                true,
            ))
        }
        iced::Event::Touch(iced::touch::Event::FingerLost { id, position }) => {
            let released_pressed_region = pressed_region.take();
            let capture_layout_bounds = released_pressed_region
                .as_ref()
                .map(|capture| capture.layout_bounds_for_capture(layout_bounds))
                .unwrap_or(layout_bounds);
            let region = released_pressed_region
                .as_ref()
                .and_then(|capture| hit_region_by_id(presentation, &capture.region_id))
                .or_else(|| hit_region_at_point(presentation, layout_bounds, *position))?;

            Some(captured_pointer_event_for_hit_region_with_details(
                region,
                presentation,
                capture_layout_bounds,
                *position,
                slipway_core::PointerEventKind::Cancel,
                None,
                touch_pointer_details(*id, false),
                true,
                true,
            ))
        }
        iced::Event::Keyboard(iced::keyboard::Event::KeyPressed {
            key,
            modifiers,
            text,
            ..
        }) => {
            if !presentation.can_route_text_edit() {
                return None;
            }
            let focus = focused_focus_region(presentation, focused_region.as_ref())?;
            if let Some(text) = text {
                let event = InputEvent::Text(slipway_core::TextInputEvent {
                    target: focus_target(focus),
                    target_slot: focus.address.clone(),
                    text: text.to_string(),
                });
                Some(IcedRoutedInput {
                    input: Some(backend_focus_input_event(
                        presentation,
                        focus,
                        DeclaredEventDispatchKind::Text,
                        None,
                        event,
                    )),
                    capture_event: true,
                    request_redraw: true,
                    refusal: None,
                })
            } else {
                let event = InputEvent::Keyboard(slipway_core::KeyboardEvent {
                    target: focus_target(focus),
                    target_slot: focus.address.clone(),
                    key: iced_keyboard_key_label(key),
                    kind: slipway_core::KeyEventKind::Press,
                    modifiers: modifiers_from_iced(*modifiers),
                    details: slipway_core::KeyboardDetails {
                        logical_key: Some(iced_keyboard_key_label(key)),
                        physical_key: None,
                        text: None,
                        repeat: false,
                        location: slipway_core::KeyLocation::Unknown,
                    },
                });
                Some(IcedRoutedInput {
                    input: Some(backend_focus_input_event(
                        presentation,
                        focus,
                        DeclaredEventDispatchKind::Keyboard,
                        None,
                        event,
                    )),
                    capture_event: true,
                    request_redraw: false,
                    refusal: None,
                })
            }
        }
        iced::Event::Keyboard(iced::keyboard::Event::KeyReleased { key, modifiers, .. }) => {
            if !presentation.can_route_text_edit() {
                return None;
            }
            let focus = focused_focus_region(presentation, focused_region.as_ref())?;
            let event = InputEvent::Keyboard(slipway_core::KeyboardEvent {
                target: focus_target(focus),
                target_slot: focus.address.clone(),
                key: iced_keyboard_key_label(key),
                kind: slipway_core::KeyEventKind::Release,
                modifiers: modifiers_from_iced(*modifiers),
                details: slipway_core::KeyboardDetails {
                    logical_key: Some(iced_keyboard_key_label(key)),
                    physical_key: None,
                    text: None,
                    repeat: false,
                    location: slipway_core::KeyLocation::Unknown,
                },
            });
            Some(IcedRoutedInput {
                input: Some(backend_focus_input_event(
                    presentation,
                    focus,
                    DeclaredEventDispatchKind::Keyboard,
                    None,
                    event,
                )),
                capture_event: true,
                request_redraw: false,
                refusal: None,
            })
        }
        _ => hover_changed.then_some(IcedRoutedInput {
            input: None,
            capture_event: false,
            request_redraw: true,
            refusal: None,
        }),
    }
}

fn sync_hover_region(
    presentation: &IcedPresentationState,
    layout_bounds: iced::Rectangle,
    cursor: iced::advanced::mouse::Cursor,
    hovered_region: &mut Option<slipway_core::PresentationRegionId>,
) -> bool {
    let next = cursor
        .position()
        .and_then(|position| interactive_region_id_at_point(presentation, layout_bounds, position));

    set_region_id(hovered_region, next)
}

fn set_region_id(
    current: &mut Option<slipway_core::PresentationRegionId>,
    next: Option<slipway_core::PresentationRegionId>,
) -> bool {
    if *current == next {
        false
    } else {
        *current = next;
        true
    }
}

fn interactive_region_id_at_point(
    presentation: &IcedPresentationState,
    layout_bounds: iced::Rectangle,
    position: iced::Point,
) -> Option<slipway_core::PresentationRegionId> {
    hit_region_at_point(presentation, layout_bounds, position)
        .map(|region| region.id.clone())
        .or_else(|| {
            focus_region_at_point(presentation, layout_bounds, position)
                .map(|region| region.id.clone())
        })
}

fn pointer_event_for_hit_region(
    region: &HitRegionDeclaration,
    presentation: &IcedPresentationState,
    layout_bounds: iced::Rectangle,
    position: iced::Point,
    kind: slipway_core::PointerEventKind,
    button: Option<iced::mouse::Button>,
    capture_event: bool,
    request_redraw: bool,
) -> IcedRoutedInput {
    pointer_event_for_hit_region_with_details(
        region,
        presentation,
        layout_bounds,
        position,
        kind,
        button.map(pointer_button),
        pointer_details(button),
        capture_event,
        request_redraw,
    )
}

#[allow(clippy::too_many_arguments)]
fn captured_pointer_event_for_hit_region_with_details(
    region: &HitRegionDeclaration,
    presentation: &IcedPresentationState,
    layout_bounds: iced::Rectangle,
    position: iced::Point,
    kind: slipway_core::PointerEventKind,
    button: Option<slipway_core::PointerButton>,
    details: slipway_core::PointerDetails,
    capture_event: bool,
    request_redraw: bool,
) -> IcedRoutedInput {
    let points = iced_input_root_local_points(presentation, layout_bounds, position);
    let root_local_position =
        hit_region_root_local_position_for_input(presentation, region, points);
    captured_pointer_event_for_hit_region_with_details_at_root(
        region,
        presentation,
        root_local_position,
        kind,
        button,
        details,
        capture_event,
        request_redraw,
    )
}

#[allow(clippy::too_many_arguments)]
fn captured_pointer_event_for_hit_region_with_details_at_root(
    region: &HitRegionDeclaration,
    presentation: &IcedPresentationState,
    root_local_position: Point,
    kind: slipway_core::PointerEventKind,
    button: Option<slipway_core::PointerButton>,
    details: slipway_core::PointerDetails,
    capture_event: bool,
    request_redraw: bool,
) -> IcedRoutedInput {
    let evidence_position = iced_evidence_root_local_point(presentation, root_local_position);
    let uses_mounted_context =
        iced_dispatch_uses_mounted_context(&presentation.dispatch_context, region);
    let dispatch_position = iced_dispatch_root_local_position(
        uses_mounted_context,
        root_local_position,
        evidence_position,
    );
    let dispatch_geometry_index = if uses_mounted_context {
        &presentation.dispatch_context.geometry_index
    } else {
        &presentation.geometry_index
    };
    let dispatch_hit_regions =
        iced_dispatch_hit_regions(&presentation.dispatch_context, region, uses_mounted_context);
    let (dispatch, evidence) =
        slipway_core::resolve_declared_captured_pointer_dispatch_with_evidence_and_geometry_index(
            EvidenceSource::backend_presented(ICED_BACKEND_ID, "physical-input"),
            presentation.frame.clone(),
            dispatch_geometry_index,
            dispatch_hit_regions.as_ref(),
            &region.id,
            dispatch_position,
            kind,
            button,
            details,
            capture_event,
        );
    let input = dispatch
        .filter(|dispatch| dispatch.selected_region == region.id)
        .map(|dispatch| {
            let mut input = BackendInputEvent::declared(dispatch.input, evidence);
            set_backend_input_evidence_position(&mut input, evidence_position);
            input
        });
    let resolved = input.is_some();
    IcedRoutedInput {
        input,
        capture_event: capture_event && resolved,
        request_redraw: request_redraw && resolved,
        refusal: None,
    }
}

fn pointer_event_for_hit_region_with_details(
    region: &HitRegionDeclaration,
    presentation: &IcedPresentationState,
    layout_bounds: iced::Rectangle,
    position: iced::Point,
    kind: slipway_core::PointerEventKind,
    button: Option<slipway_core::PointerButton>,
    details: slipway_core::PointerDetails,
    capture_event: bool,
    request_redraw: bool,
) -> IcedRoutedInput {
    let points = iced_input_root_local_points(presentation, layout_bounds, position);
    let root_local_position =
        hit_region_root_local_position_for_input(presentation, region, points);
    pointer_event_for_hit_region_with_details_at_root(
        region,
        presentation,
        root_local_position,
        kind,
        button,
        details,
        capture_event,
        request_redraw,
    )
}

#[allow(clippy::too_many_arguments)]
