        let root = WidgetId::from("mounted-touch-root");
        let child = TestWidget.id();
        let child_slot = WidgetSlotAddress::new(root.clone(), 0).child(child.clone(), 0);
        let root_origin = Point { x: 24.0, y: 18.0 };
